// // This module toggles its output every two clock cycles instead of one
module crystal_oscillator (  
    input wire clk,  
    input wire reset,  
    output reg out  
);  
    always @(posedge clk or posedge reset) begin  
        if (reset) begin  
            out <= 0;  
        end else begin  
            out <= ~out;  
        end  
    end  
endmodule
